const PRODUCT = 'Vortex';
return [
  { json: { url: `http://localhost:8000/scrape/reddit?q=${PRODUCT}`, platform: 'reddit' } },
  { json: { url: `http://localhost:8000/scrape/twitter?q=${PRODUCT}`, platform: 'twitter' } },
  { json: { url: `http://localhost:8000/scrape/linkedin?q=${PRODUCT}`, platform: 'linkedin' } }
];

const items = $input.all();
let combinedText = '';
let sourceCounts = { reddit: 0, twitter: 0, linkedin: 0 };

items.forEach(item => {
  combinedText += `\n--- PLATFORM: ${item.json.platform} ---\n${item.json.data}\n`;
  // Basic heuristic: check if data contains content to count as a source
  if (item.json.data && item.json.data.length > 50) {
    sourceCounts[item.json.platform] = (sourceCounts[item.json.platform] || 0) + 1;
  }
});

return [{ json: { body: combinedText, sourceCounts } }];

