const groqResponse = $input.first().json;
const content = groqResponse.choices[0].message.content;
let intel;
try {
  intel = JSON.parse(content.replace(/```json|```/g, '').trim());
} catch(e) {
  intel = { summary: 'Error parsing AI response', sentiment_score: 50, sources: { reddit: 1 } };
}

// Helper to format for Firestore REST API
const toFs = (val) => {
  if (typeof val === 'string') return { stringValue: val };
  if (typeof val === 'number') return { doubleValue: val };
  if (Array.isArray(val)) return { arrayValue: { values: val.map(v => ({ mapValue: { fields: Object.fromEntries(Object.entries(v).map(([k,v]) => [k, toFs(v)])) } })) } };
  if (typeof val === 'object') return { mapValue: { fields: Object.fromEntries(Object.entries(val).map(([k,v]) => [k, toFs(v)])) } };
  return { stringValue: String(val) };
};

const fields = Object.fromEntries(Object.entries(intel).map(([k, v]) => [k, toFs(v)]));
return [{ json: { fields } }];
